devicemanagement_pair_wizard_title_running = TextObject(bs_BA="Povezivanje sa glavnim uređajem u toku...", cs_CZ="Připojování hlavního zařízení probíhá...", da_DK="Oprettelse af forbindelse for primært apparat i gang...", de_DE="Hauptgerätverbindung läuft...", el_GR="Σύνδεση βασικής συσκευής σε εξέλιξη...", en_GB="Connecting main device...", es_ES="Conectando dispositivo principal...", fi_FI="Päälaitetta yhdistetään...", fr_FR="Connexion du périphérique principal en cours...", hr_HR="Spajanje glavnog uređaja je u tijeku...", hu_HU="A főkészülék csatlakoztatása folyamatban...", it_IT="Collegamento del dispositivo principale in corso...", nl_NL="Verbinding met hoofdapparaat is bezig...", no_NO="Hovedenhetforbindelse opprettes...", pl_PL="Trwa podłączanie urządzenia głównego...", pt_PT="Ligação do aparelho principal em curso...", ro_RO="Conectare dispozitiv principal în curs...", ru_RU="Выполняется подключение основного устройства...", sk_SK="Pripojenie hlavného zariadenia prebieha...", sl_SI="Povezovanje glavne naprave ...", sr_RS="Povezivanje sa glavnim uređajem u toku...", sv_SE="Anslutning till huvudenheten pågår...", tr_TR="Ana cihaz bağlantısı sürüyor...", uk_UA="Триває підключення основного пристрою...")
devicemanagement_pair_wizard_title_start = TextObject(bs_BA="Pokretanje povezivanja s glavnim uređajem", cs_CZ="Zahájit připojování hlavního zařízení", da_DK="Start oprettelse af forbindelse for primært apparat", de_DE="Hauptgerätverbindung starten", el_GR="Έναρξη σύνδεσης βασικής συσκευής", en_GB="Start main device connection", es_ES="Conectar dispositivo principal", fi_FI="Käynnistä päälaitteen yhdistäminen", fr_FR="Lancer la connexion du périphérique principal", hr_HR="Pokrenuti spajanje glavnog uređaja", hu_HU="A főkészülék csatlakoztatásának indítása", it_IT="Avvia collegamento del dispositivo principale", nl_NL="Verbinding met hoofdapparaat maken", no_NO="Start opprettelse av hovedenhetforbindelse", pl_PL="Uruchom podłączanie urządzenia głównego", pt_PT="Iniciar ligação do aparelho principal", ro_RO="Iniţiere conectare dispozitiv principal", ru_RU="Начать подключение основного устройства", sk_SK="Spustiť pripojenie hlavného zariadenia", sl_SI="Zagon povezovanja glavne naprave", sr_RS="Pokretanje povezivanja sa glavnim uređajem", sv_SE="Starta anslutning till huvudenhet", tr_TR="Ana cihaz bağlantısını başlat", uk_UA="Розпочати підключення основного пристрою")
devicemanagement_unpair_wizard_confirm_text = TextObject(bs_BA="Prilikom odvajanja glavnog uređaja, brišu se svi digitalni ključevi i više se ne mogu koristiti kao ključevi vozila. Da li zaista\nželite odvojiti glavni uređaj?", cs_CZ="Při odpojení hlavního zařízení se všechny digitální klíčky smažou a nebude je již možné používat jako klíčky od vozidla. \nChcete hlavní zařízení opravdu odpojit?", da_DK="Når det primære apparat afbrydes, slettes alle digitale nøgler, og de kan ikke længere anvendes som bilnøgler.  Vil du\nvirkelig afbryde det primære apparat.", de_DE="Beim Trennen des Hauptgeräts werden alle digitalen Schlüssel gelöscht und können nicht mehr als Fahrzeugschlüssel\ngenutzt werden.  Möchtest du das Hauptgerät wirklich trennen?", el_GR="Κατά την αποσύνδεση της βασικής συσκευής θα διαγραφούν όλα τα ψηφιακά κλειδιά και δεν θα μπορούν πλέον να\nχρησιμοποιηθούν ως κλειδιά οχήματος.  Θέλετε σίγουρα να αποσυνδέσετε τη βασική συσκευή;", en_GB="If you remove the main device, all digital keys will be deleted and can no longer be used as vehicle keys.  Do you really\nwant to remove the main device?", es_ES="Al desconectar el dispositivo principal se borran todas las llaves digitales y ya no se pueden utilizar como llave del\nvehículo.  ¿Realmente desea desconectar el dispositivo principal?", fi_FI="Kun päälaite erotetaan, kaikki digitaaliset avaimet poistetaan eikä niitä voi enää käyttää autonavaimina.  Haluatko\nvarmasti erottaa päälaitteen?", fr_FR="Lors de la déconnexion du périphérique principal toutes les clés numériques sont effacées et ne peuvent plus être\nutilisées comme clés du véhicule.  Souhaitez-vous vraiment déconnecter le périphérique principal?", hr_HR="Kod odvajanja glavnog uređaja svi se digitalni ključevi brišu i više se ne mogu koristiti kao ključevi vozila.  Želite li uistinu\nodvojiti glavni uređaj?", hu_HU="A főkészülék leválasztásakor az összes digitális kulcs törlődik, és ezután már nem használható járműkulcsként.  Biztosan\nle szeretnéd választani a főkészüléket?", it_IT="Scollegando il dispositivo principale, tutte le chiavi digitali verranno cancellate e non potranno più essere utilizzate\ncome chiavi della vettura.  Desidera davvero scollegare il dispositivo principale?", nl_NL="Bij het ontkoppelen van het hoofdapparaat worden alle digitale sleutels gewist en kunnen er niet meer dan\nvoertuigsleutels worden gebruikt.  Wil je het hoofdapparaat echt loskoppelen?", no_NO="Når hovedenheten kobles fra, blir alle digitale nøkler slettet og kan ikke lenger brukes som bilnøkkel.  Er du sikker på at\ndu vil koble fra hovedenheten?", pl_PL="Przy odłączeniu urządzenia głównego wszystkie kluczyki cyfrowe zostaną usunięte i nie będzie można korzystać z nich\njako kluczyków do pojazdu.  Czy na pewno chcesz odłączyć urządzenie główne?", pt_PT="Ao desligar o aparelho principal todas as chaves digitais serão eliminadas e já não podem ser utilizadas como chave do\nveículo.  Desejas mesmo desligar o aparelho principal?", ro_RO="La deconectarea dispozitivului principal, toate cheile digitale vor fi şterse şi nu vor mai putea fi utilizate ca şi cheie a\nautovehiculului.  Doriţi într-adevăr să deconectaţi dispozitivul principal?", ru_RU="При разъединении подключения основного устройства все цифровые ключи удаляются и больше не могут\nиспользоваться в качестве ключей автомобиля.  Вы действительно хотите разъединить подключение основного\nустройства?", sk_SK="Pri odpájaní hlavného zariadenia sa všetky digitálne kľúče vymažú a už sa nie je možné ich použiť ako kľúče od vozidla.\nSkutočne chcete odpojiť hlavné zariadenie?", sl_SI="Pri prekinitvi povezave z glavno napravo se vsi digitalni ključi izbrišejo in jih ni več mogoče uporabljati kot ključ vozila.  Ali\nres želite prekiniti povezavo z glavno napravo?", sr_RS="Prilikom odvajanja glavnog uređaja, brišu se svi digitalni ključevi i više se ne mogu koristiti kao ključevi vozila. Da li zaista\nželite odvojiti glavni uređaj?", sv_SE="När huvudenheten ansluts raderas alla digitala nycklar och kan inte längre användas som fordonsnyckel.  Vill du\nverkligen koppla från huvudenheten?", tr_TR="Ana cihazın ayrılması sırasında tüm dijital anahtarlar silinir ve artık araç anahtarı olarak kullanılamazlar.  Ana cihazı\ngerçekten ayırmak istiyor musun?", uk_UA="У разі роз’єднання підключення основного пристрою всі цифрові ключі видаляються і більше не можуть\nвикористовуватися як ключі від автомобіля. Дійсно роз'єднати підключення основного пристрою?")
